return items.map(item => {
  const root = item.json || {};
  const envelope = root.body && typeof root.body === 'object' ? root.body : root;
  const msg = envelope.message || envelope.data || root.message || root.data || {};

  const findDeep = (obj, predicate) => {
    const seen = new Set();
    const stack = [obj];
    while (stack.length) {
      const cur = stack.pop();
      if (!cur || typeof cur !== 'object') continue;
      if (seen.has(cur)) continue;
      seen.add(cur);
      if (predicate(cur)) return cur;
      for (const v of Object.values(cur)) {
        if (v && typeof v === 'object') stack.push(v);
      }
    }
    return null;
  };

  const callObj = msg.call || envelope.call || root.call ||
    findDeep(msg, (x) => x.id && (x.startedAt || x.endedAt || x.customer || x.metadata));

  const metadata = (callObj && callObj.metadata) || msg.metadata || envelope.metadata || root.metadata || {};

  const startedAt = (callObj && callObj.startedAt) || msg.startedAt || envelope.startedAt || root.startedAt || null;
  const endedAt = (callObj && callObj.endedAt) || msg.endedAt || envelope.endedAt || root.endedAt || null;
  const endedReason = msg.endedReason || envelope.endedReason || root.endedReason || null;
  const eventType = msg.type || envelope.type || root.type || null;
  const callId = (callObj && callObj.id) || msg.id || envelope.id || root.id || null;
  const customer = (callObj && callObj.customer) || msg.customer || envelope.customer || root.customer || {};

  const transcript = msg.transcript || envelope.transcript || root.transcript ||
    (msg.artifact && msg.artifact.transcript) || null;
  const recordingUrl = msg.recordingUrl || envelope.recordingUrl || root.recordingUrl ||
    (msg.artifact && msg.artifact.recordingUrl) || null;
  const summary = msg.summary || envelope.summary || root.summary || null;

  const durationMs = msg.durationMs || envelope.durationMs || root.durationMs || null;
  const durationSeconds = msg.durationSeconds || envelope.durationSeconds || root.durationSeconds ||
    (durationMs ? Math.round(durationMs / 1000) : null);

  const cost = msg.cost || envelope.cost || root.cost || 0;

  const artifact = msg.artifact || envelope.artifact || root.artifact || {};
  const structuredOutputs = artifact.structuredOutputs || msg.structuredOutputs ||
    envelope.structuredOutputs || root.structuredOutputs || {};

  const transfers = artifact.transfers || msg.transfers || envelope.transfers || root.transfers || [];

  item.json = {
    id_negocio: metadata.id_negocio || null,
    cedula: metadata.cedula || null,
    id_llamada: callId || null,
    event_type: eventType,
    endedReason: endedReason,
    startedAt: startedAt,
    endedAt: endedAt,
    transcript: transcript,
    recordingUrl: recordingUrl,
    summary: summary,
    durationMs: durationMs,
    durationSeconds: durationSeconds,
    cost: cost,
    customer_number: customer.number || null,
    customer_name: customer.name || null,
    metadata: metadata,
    artifact: artifact,
    structuredOutputs: structuredOutputs,
    transfers: transfers,
    _raw: envelope
  };
  return item;
});

return items.map(item => {
  const root = item.json || {};
  const structuredOutputs = root.structuredOutputs || {};
  let out = {
    nomenclatura: null,
    motivo: null,
    es_familiar: null,
    contactoalo: null,
    contactoefectivo: null,
    sentimiento: null,
    resumen_llamada: root.summary || null,
    interes_llamada_ejecutivo: null
  };

  const tryParse = (val) => {
    if (!val) return val;
    if (typeof val === 'object' && !Array.isArray(val)) return val;
    if (typeof val === 'string' && (val.trim().startsWith('{') || val.trim().startsWith('['))) {
      try { return JSON.parse(val); } catch (e) {}
    }
    return val;
  };

  const normalize = (name) => String(name || '').toLowerCase().replace(/[\s_]+/g, '');

  for (const [uuid, output] of Object.entries(structuredOutputs)) {
    const name = normalize(output.name);
    const result = tryParse(output.result);

    if (name === 'estadogestionutpl' && typeof result === 'object') {
      out.nomenclatura = result.id_nomenclatura || result.nomenclatura || out.nomenclatura;
      out.motivo = result.id_motivo || result.motivo || out.motivo;
    }
    if (name === 'sentimientocliente') {
      out.sentimiento = typeof result === 'string' ? result : null;
    }
    if (name === 'esfamiliar') {
      out.es_familiar = typeof result === 'string' ? result : null;
    }
    if (name === 'contactoalo') {
      out.contactoalo = typeof result === 'string' ? result : null;
    }
    if (name === 'contactoefectivo') {
      out.contactoefectivo = typeof result === 'string' ? result : null;
    }
    if (name === 'resumenllamada') {
      out.resumen_llamada = typeof result === 'string' ? result : (result?.resumen || out.resumen_llamada);
    }
    if (name === 'interescontactoejecutivo') {
      out.interes_llamada_ejecutivo = typeof result === 'string' ? result : null;
    }
  }

  if (!out.interes_llamada_ejecutivo) {
    out.interes_llamada_ejecutivo = 'NO_APLICA';
  }

  for (const [k, v] of Object.entries(out)) {
    if (v !== undefined) item.json[k] = v;
  }

  return item;
});

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const nom = String(item.json.nomenclatura || '').trim().toUpperCase();
  const retryNoms = cfg.retryNomenclaturas || ['NC', 'VLL'];

  if (retryNoms.includes(nom)) {
    item.json.status_sugerido = 'REINTENTAR';
    item.json.estado_flujo = cfg.states.retry;
  } else {
    item.json.status_sugerido = 'FINAL';
    item.json.estado_flujo = cfg.states.done;
  }

  return item;
});

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const raw = String(item.json.id_negocio ?? '').trim();
  if (!raw) {
    item.json.query = `SELECT 'skip_no_id_negocio' AS status`;
    return item;
  }

  const id_negocio = raw.replace(/'/g, '''');
  const estado = String(item.json.estado_flujo || cfg.states.done).replace(/'/g, '''');

  item.json.query = `
    UPDATE ${cfg.db.schema}.${cfg.db.table}
    SET estado_flujo = '${estado}',
        updated_at = now()
    WHERE id_negocio = '${id_negocio}'
    RETURNING *;
  `;

  return item;
});

