return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const nom = String(item.json.id_nomenclatura || '').trim().toUpperCase();
  const texto = (String(item.json.resumen_llamada || '') + ' ' + String(item.json.transcripcion_llamada || '')).toLowerCase();

  const defaultMotivo = { id: 'f6cf9978-e0e0-4cd9-9605-3e4baca78289', name: 'NIN - No Desea Continuar Con Proceso Matricula' };
  let selected = defaultMotivo;
  const dealstage = cfg.crmUtpl.dealstage[nom] || cfg.crmUtpl.dealstage.NIN;

  if (nom === 'NIN') {
    for (const m of motivosNIN) {
      if (m.keys.split(',').some(k => texto.includes(k.trim()))) {
        selected = { id: m.id, name: m.name };
        break;
      }
    }
  } else if (nom === 'NC') {
    selected = { id: '569d4307-4da7-45e0-9c5a-7530a99aca5d', name: 'NC - No Contacto' };
  }

  item.json.crmDealstage = dealstage;
  item.json.crmDisposition = selected.id;
  item.json.crmSalesStage = selected.name;
  return item;
});

const escapeXml = function(str) {
  return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&apos;');
};

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;

  const codigo_negocio = String(item.json.id_negocio || '').trim();
  const dealstage = String(item.json.crmDealstage || '');
  const hs_call_disposition = String(item.json.crmDisposition || '');
  const hs_call_body = String(item.json.resumen_llamada || '').substring(0, 500);
  const agent_name = cfg.crmUtpl.agentName;
  const hs_call_duration = String(item.json.duracion_llamada || '0');
  const sales_stage_detail = String(item.json.crmSalesStage || '');
  const commitment_date = (item.json.fecha_reagenda || '').toString().slice(0, 10) || '';
  const dealid = String(item.json.id_interno_negocio || '');
  const hs_timestamp = String(item.json.fecha_gestion || '') + ' ' + String(item.json.hora_gestion || '');
  const scheduling_date = '';

  item.json.soapXml = `<?xml version="1.0" encoding="utf-8"?>
<soap:Envelope xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xmlns:xsd="http://www.w3.org/2001/XMLSchema" xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <RegistrarLLamada xmlns="http://tempuri.org/">
      <codigo_negocio>${escapeXml(codigo_negocio)}</codigo_negocio>
      <dealstage>${escapeXml(dealstage)}</dealstage>
      <hs_call_disposition>${escapeXml(hs_call_disposition)}</hs_call_disposition>
      <hs_call_body>${escapeXml(hs_call_body)}</hs_call_body>
      <agent_name>${escapeXml(agent_name)}</agent_name>
      <hs_call_duration>${escapeXml(hs_call_duration)}</hs_call_duration>
      <sales_stage_detail>${escapeXml(sales_stage_detail)}</sales_stage_detail>
      <commitment_date>${escapeXml(commitment_date)}</commitment_date>
      <dealid>${escapeXml(dealid)}</dealid>
      <hs_timestamp>${escapeXml(hs_timestamp)}</hs_timestamp>
      <scheduling_date>${escapeXml(scheduling_date)}</scheduling_date>
    </RegistrarLLamada>
  </soap:Body>
</soap:Envelope>`;

  return item;
});

return items.map(item => {
  const body = String(item.json.response || item.json.body || '');
  const hc = body.match(/<httpCode>(\d+)<\/httpCode>/);
  const ir = body.match(/<idreturn>([^<]+)<\/idreturn>/);
  const m1 = body.match(/<messagews1>([^<]*)<\/messagews1>/);
  const m2 = body.match(/<messagews2>([^<]*)<\/messagews2>/);
  const m3 = body.match(/<messagews3>([^<]*)<\/messagews3>/);

  item.json.crmHttpCode = hc ? hc[1] : null;
  item.json.crmIdReturn = ir ? ir[1] : null;
  item.json.crmSuccess = item.json.crmHttpCode === '201';

  if (!item.json.crmSuccess) {
    item.json.crmError = [m1 ? m1[1] : null, m2 ? m2[1] : null, m3 ? m3[1] : null].filter(Boolean).join(' | ');
  }

  const esc = function(s) { return String(s || '').replace(/'/g, "''"); };
  item.json.crmInsertQuery = `INSERT INTO public.utpl_crm (id_negocio, flujo_origen, nomenclatura, dealstage, hs_call_disposition, sales_stage_detail, agent_name, hs_call_duration, hs_call_body, commitment_date, dealid, hs_timestamp, scheduling_date, soap_xml, http_code, id_return, error_messages) VALUES ('${esc(item.json.id_negocio)}', 'CierreLlamadas', '${esc(item.json.id_nomenclatura)}', '${esc(item.json.crmDealstage)}', '${esc(item.json.crmDisposition)}', '${esc(item.json.crmSalesStage)}', '${esc(item.json.crmAgent || 'ARIA UTPL')}', '${esc(item.json.duracion_llamada)}', '${esc((item.json.resumen_llamada || '').substring(0, 500))}', '${esc((item.json.fecha_reagenda || '').toString().slice(0, 10))}', '${esc(item.json.id_interno_negocio)}', '${esc(item.json.fecha_gestion + ' ' + item.json.hora_gestion)}', NULL, '${esc(item.json.soapXml)}', '${esc(item.json.crmHttpCode)}', '${esc(item.json.crmIdReturn)}', '${esc(item.json.crmError)}')`;

  return item;
});

return items.map(item => {
  const url = String(item.json.link_audio_vapi || '');
  item.json.ext = url.toLowerCase().includes('.wav') ? 'wav' : 'mp3';
  return item;
});

return items.map(item => {
  const tokenRow = item.json;
  const token = tokenRow.value || null;
  const expiresAt = tokenRow.expires_at || null;

  let needsRefresh = true;
  if (token && expiresAt) {
    if (new Date(expiresAt) > new Date()) {
      needsRefresh = false;
      item.json.altivaToken = token;
    }
  }

  item.json.tokenNeedsRefresh = needsRefresh;
  return item;
});

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const nom = String(item.json.id_nomenclatura || '').trim().toUpperCase();
  const nodo = cfg.altiva.nodoMapping[nom] || '1';

  item.json.altivaBody = {
    nuic: String(item.json.cedula || ''),
    nombre_corto_campania: String(item.json.nombre_corto_campania || cfg.altiva.nombreCampania || ''),
    nodo: nodo
  };

  const token = item.json.altivaToken || (item.json.data && item.json.data.access_token) || '';
  if (!item.json.altivaToken && item.json.data && item.json.data.access_token) {
    item.json.altivaToken = String(item.json.data.access_token);
  }

  return item;
});

return items.map(item => {
  const body = item.json.response || item.json;
  let status = null, message = '';
  try {
    const parsed = typeof body === 'string' ? JSON.parse(body) : body;
    status = parsed.estado || null;
    message = parsed.mensaje || '';
  } catch (e) {
    message = String(body || '').substring(0, 200);
  }

  item.json.altivaStatus = status;
  item.json.altivaMessage = message;
  item.json.altivaSuccess = status === 200;

  return item;
});
